import{_ as a,o as t,c as s,ae as r}from"./chunks/framework.B6gjLfeO.js";const d=JSON.parse('{"title":"iMessage Apps","description":"","frontmatter":{"title":"iMessage Apps","slug":"imessage-apps"},"headers":[],"relativePath":"developer-hub/imessage-apps.md","filePath":"developer-hub/imessage-apps.md"}'),o={name:"developer-hub/imessage-apps.md"};function i(n,e,p,l,h,c){return t(),s("div",null,[...e[0]||(e[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>With iOS 10, Branch has <a href="https://blog.branch.io/setting-up-your-ios-10-imessages-app-with-attribution-and-deep-linking" target="_blank" rel="noreferrer">added support</a> for extension type apps so that you can bundle the SDK into your iMessage app. Apple didn&#39;t build full deep linking support into extension apps, so unfortunately the use cases are limited to driving new installs for now. We&#39;ll wait patiently to observe updates over time.</p><p>iMessage apps are now completely separate from your main App Store app, and should be treated as such. Thus, there is some common confusion that we wanted to clear up regarding how to use Branch with your iMessage app. Here&#39;s a list of best practices to ensure your integration is successful.</p><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><h2 id="best-practices" tabindex="-1">Best practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best practices&quot;">​</a></h2><h3 id="create-a-separate-branch-app-for-the-messages-app" tabindex="-1">Create a separate Branch app for the messages app <a class="header-anchor" href="#create-a-separate-branch-app-for-the-messages-app" aria-label="Permalink to &quot;Create a separate Branch app for the messages app&quot;">​</a></h3><p>We highly recommend that you create a <em>separate</em> Branch app via the dashboard for your iMessage app than your full iOS app. Why? Because there&#39;s no technical way to handle deep link routing elegantly between your core app and the messages app. Apple has not built support for this use case.</p><p>Configure one Branch app&#39;s settings to link to your messages app in the iMessage App Store, then configure another Branch app settings to link to your core app in the main App Store. This means you&#39;ll integrate the SDK into your messages app with a different Branch key than your main app.</p><h3 id="only-use-branch-for-driving-installs-of-messages-apps" tabindex="-1">Only use Branch for driving installs of messages apps <a class="header-anchor" href="#only-use-branch-for-driving-installs-of-messages-apps" aria-label="Permalink to &quot;Only use Branch for driving installs of messages apps&quot;">​</a></h3><p>Apple did not build support for the use case where a user clicks a link and the messages app opens. Therefore, Branch cannot open up the existing, pre-installed messages app. Branch can only link to the messages app in the iMessage App Store, even when it&#39;s already installed.</p><p>Because of this, you should primarily use Branch for tracking installs and deep linking through install. Don&#39;t expect a high quality user experience if the app is already installed.</p><h3 id="market-your-messages-app-separately-from-your-main-app" tabindex="-1">Market your messages app separately from your main app <a class="header-anchor" href="#market-your-messages-app-separately-from-your-main-app" aria-label="Permalink to &quot;Market your messages app separately from your main app&quot;">​</a></h3><p>Because there&#39;s no good way to intelligently route to the main App Store, iMessages App Store and existing app depending on the context, we recommend you market your messages app with different links from your main App Store app. So, message to a user you&#39;re going to link them to your messages app differently than when you&#39;re linking to the App Store app.</p><h2 id="configuring-redirects" tabindex="-1">Configuring redirects <a class="header-anchor" href="#configuring-redirects" aria-label="Permalink to &quot;Configuring redirects&quot;">​</a></h2><h3 id="introductory-concept-on-messages-redirects" tabindex="-1">Introductory concept on messages redirects <a class="header-anchor" href="#introductory-concept-on-messages-redirects" aria-label="Permalink to &quot;Introductory concept on messages redirects&quot;">​</a></h3><p>If you&#39;ve read the above, you know that the iMessage App Store is a completely different store than the main App Store. In order to link users to your app in the iMessage App Store, you simply need to append <code>?app=messages</code> to the link. You can try this on any iOS 10 phone with the links below:</p><ol><li>iMessages App Store: <a href="https://itunes.apple.com/us/app/classic-mac/id1127542169?app=messages" target="_blank" rel="noreferrer">https://itunes.apple.com/us/app/classic-mac/id1127542169?app=messages</a></li><li>Main App Store: <a href="https://itunes.apple.com/us/app/classic-mac/id1127542169" target="_blank" rel="noreferrer">https://itunes.apple.com/us/app/classic-mac/id1127542169</a></li></ol><h4 id="configure-your-branch-links" tabindex="-1">Configure your Branch Links <a class="header-anchor" href="#configure-your-branch-links" aria-label="Permalink to &quot;Configure your Branch Links&quot;">​</a></h4><p>First, create an entirely new app via the <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch dashboard</a>. You can do this in the pull down selector that shows your app name in the top right section. Then head to the <a href="https://dashboard.branch.io/link-settings" target="_blank" rel="noreferrer">link settings page</a> and scroll to the iOS section to configure it as follows:</p><p><em>[Image: 1860]</em></p><p>dashboard settings</p><p>Ensure you do the following:</p><ul><li>Uncheck “I have an iOS App”</li><li>Disable Universal Links</li><li>Paste the App Store URL with <code>?app=messages</code> appended into the URL field</li><li>Click Save</li></ul><p>You&#39;re all set! All of your Branch Links will correctly link to the iMessages App Store.</p><h3 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h3><h3 id="tracking-installs" tabindex="-1">Tracking installs <a class="header-anchor" href="#tracking-installs" aria-label="Permalink to &quot;Tracking installs&quot;">​</a></h3><p>To track installs and personalize the first time user experience, you simply need to follow the instructions in the <a href="./ios-sdk-overview.html">SDK integration guide</a> for iMessage apps. You&#39;ll integrate the SDK just as you have for your main App Store app.</p>',27)])])}const g=a(o,[["render",i]]);export{d as __pageData,g as default};
